mapper.select:
SELECT COUNT(*)
FROM mhdb.TB_USER_INFO
WHERE USER_CD = #{userCd}

mapper.update:
UPDATE mhdb.TB_USER_INFO SET USER_NM = #{userNm}, EXPIRE_DATE = #{expireDate}, TELEPHONE = #{telephone}, USE_YN = #{useYn}, EMAIL = #{email}, BRC = #{brc}, BRNM = #{brnm}, IP_ADDRESS = #{ipAddress}
, PASSWORD = #{password}
, PICTURE = #{picture}
WHERE USER_ID = #{userId}::integer

mapper.delete:
DELETE FROM mhdb.TB_APPROVAL_REQ
WHERE USER_CD = #{userCd}
  AND APPROVAL_DIV_CD = '01'

DELETE FROM mhdb.TB_APPROVAL_LINE
WHERE USER_CD = #{userCd}
  AND APPROVAL_DIV_CD = '01'
